/** Resumen para la lista (sin apartados/items). */
export const DOSIERES_RESUMEN: DossierResumen[] = DOSIERES_FIXTURE.map(d => ({
  id: d.id,
  slug: d.slug,
  nombre_completo: d.nombre_completo,
  alias: d.alias,
  cargo_actual: d.cargo_actual,
  partido: d.partido,
  foto_url: d.foto_url,
  bio_corta: d.bio_corta,
  tags: d.tags,
  n_apartados: d.apartados.length,
  updated_at: d.updated_at,
}))

export function getDossierBySlug(slug: string): DossierCompleto | null {
  return DOSIERES_FIXTURE.find(d => d.slug === slug) ?? null
}
